	input 		          		UART_RXD,
	output		          		UART_TXD,

	//////////// SDCARD //////////
	output		          		SD_CLK,
	inout 		          		SD_CMD,
	inout 		     [3:0]		SD_DAT,
	input 		          		SD_WP_N,

	//////////// VGA //////////
	output		     [7:0]		VGA_B,
	output		          		VGA_BLANK_N,
	output		          		VGA_CLK,
	output		     [7:0]		VGA_G,
	output		          		VGA_HS,
	output		     [7:0]		VGA_R,
	output		          		VGA_SYNC_N,
	output		          		VGA_VS,

	//////////// I2C for EEPROM (I2C ADDRESS W/R = 0xA0/0xA1) //////////
	output		          		EEP_I2C_SCLK,
	inout 		          		EEP_I2C_SDAT,

	//////////// Ethernet //////////
	output		          		ENET_GTX_CLK,
	input 		          		ENET_INT_N,
	input 		          		ENET_LINK100,
	output		          		ENET_MDC,
	inout 		          		ENET_MDIO,
	output		          		ENET_RST_N,
	input 		          		ENET_RX_CLK,
	input 		          		ENET_RX_COL,
	input 		          		ENET_RX_CRS,
	input 		     [3:0]		ENET_RX_DATA,
	input 		          		ENET_RX_DV,
	input 		          		ENET_RX_ER,
	input 		          		ENET_TX_CLK,
	output		     [3:0]		ENET_TX_DATA,
	output		          		ENET_TX_EN,
	output		          		ENET_TX_ER,

	//////////// TV Decoder (I2C ADDRESS W/R = 0x40/0x41) //////////
	output		          		I2C_SCLK,
	inout 		          		I2C_SDAT,
