	output		          		SSRAM_CLK,
	output		          		SSRAM_GW_N,
	output		          		SSRAM_OE_N,
	output		          		SSRAM_WE_N,
	output		          		SSRAM0_CE_N,
	output		          		SSRAM1_CE_N,

	//////////// Flash //////////
	output		          		FL_CE_N,
	output		          		FL_OE_N,
	output		          		FL_RESET_N,
	input 		          		FL_RY,
	output		          		FL_WE_N,
	output		          		FL_WP_N,

	//////////// Data and Address bus shared by Flash & SSRAM //////////
